import{_ as i,C as c,o as d,c as s,a4 as l,b as n,w as r,a,E as u,a5 as h,j as e}from"./chunks/framework.4M7SpZrd.js";const v=JSON.parse('{"title":"Seguranca & Hardening","description":"","frontmatter":{},"headers":[],"relativePath":"seguranca/hardening.md","filePath":"seguranca/hardening.md"}'),p={name:"seguranca/hardening.md"};function m(b,t,g,f,_,k){const o=c("Mermaid");return d(),s("div",null,[t[1]||(t[1]=l(`<h1 id="seguranca-hardening" tabindex="-1">Seguranca &amp; Hardening <a class="header-anchor" href="#seguranca-hardening" aria-label="Permalink to &quot;Seguranca &amp; Hardening&quot;">​</a></h1><h2 id="ssrf-guard" tabindex="-1">SSRF Guard <a class="header-anchor" href="#ssrf-guard" aria-label="Permalink to &quot;SSRF Guard&quot;">​</a></h2><p>Arquivo: <code>app/core/ssrf_guard.py</code></p><p>Protege contra Server-Side Request Forgery em todos os pontos que fazem requests HTTP a URLs externas (crawler, monitors, evidence service, proxy endpoint).</p><h3 id="validacoes" tabindex="-1">Validacoes <a class="header-anchor" href="#validacoes" aria-label="Permalink to &quot;Validacoes&quot;">​</a></h3><ul><li>Rejeita schemes nao-HTTP(S)</li><li>Bloqueia IPs privados (RFC-1918: 10.x, 172.16-31.x, 192.168.x)</li><li>Bloqueia loopback (127.0.0.1, ::1, 0.0.0.0)</li><li>Bloqueia link-local/IMDS (169.254.169.254)</li><li>Resolve DNS e valida IPs resultantes</li></ul><h3 id="anti-toctou-dns-rebinding" tabindex="-1">Anti-TOCTOU (DNS Rebinding) <a class="header-anchor" href="#anti-toctou-dns-rebinding" aria-label="Permalink to &quot;Anti-TOCTOU (DNS Rebinding)&quot;">​</a></h3><p>Funcao <code>resolve_and_validate(url)</code> retorna <code>(is_safe, resolved_ip)</code>:</p><ul><li>Resolve DNS uma unica vez</li><li>Valida todos os IPs retornados</li><li>Retorna IP resolvido para conexao direta (bypassa segundo DNS lookup)</li><li>Executa em thread (asyncio.to_thread) para nao bloquear event loop</li></ul><h3 id="funcoes" tabindex="-1">Funcoes <a class="header-anchor" href="#funcoes" aria-label="Permalink to &quot;Funcoes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Funcao</th><th>Tipo</th><th>Uso</th></tr></thead><tbody><tr><td><code>is_safe_url(url)</code></td><td>Sync</td><td>Validacao rapida</td></tr><tr><td><code>is_safe_url_async(url)</code></td><td>Async</td><td>Validacao em contexto async</td></tr><tr><td><code>resolve_and_validate(url)</code></td><td>Async</td><td>Anti-TOCTOU com IP resolvido</td></tr></tbody></table><hr><h2 id="block-detector" tabindex="-1">Block Detector <a class="header-anchor" href="#block-detector" aria-label="Permalink to &quot;Block Detector&quot;">​</a></h2><p>Arquivo: <code>app/core/block_detector.py</code></p><p>Detecta bloqueios de anti-scraping analisando respostas HTTP. Usado pelo crawler e monitors.</p><h3 id="deteccao-em-4-camadas" tabindex="-1">Deteccao em 4 camadas <a class="header-anchor" href="#deteccao-em-4-camadas" aria-label="Permalink to &quot;Deteccao em 4 camadas&quot;">​</a></h3><ol><li><strong>Status codes</strong>: 401, 403, 429, 444, 451, 503 — tipo e confianca mapeados</li><li><strong>Empty response</strong>: body &lt; 100 bytes com status 200 — analisa conteudo</li><li><strong>Platform-specific patterns</strong>: regex por plataforma (Telegram, Instagram, Discord, Reddit, Twitter)</li><li><strong>Generic HTML patterns</strong>: captcha, challenge, access denied, rate limit, Cloudflare</li></ol><h3 id="blockdetection-result" tabindex="-1">BlockDetection result <a class="header-anchor" href="#blockdetection-result" aria-label="Permalink to &quot;BlockDetection result&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Descricao</th></tr></thead><tbody><tr><td><code>is_blocked</code></td><td><code>bool</code></td><td>Se foi detectado bloqueio</td></tr><tr><td><code>block_type</code></td><td><code>str</code></td><td>none/rate_limit/captcha/ban/geo/auth/empty/server_error</td></tr><tr><td><code>confidence</code></td><td><code>float</code></td><td>0.0-1.0</td></tr><tr><td><code>retry_after</code></td><td><code>float?</code></td><td>Segundos (de Retry-After header ou pattern match)</td></tr><tr><td><code>should_retry</code></td><td><code>bool</code></td><td>True se temporario (rate_limit ou server_error)</td></tr></tbody></table><hr><h2 id="circuit-breaker" tabindex="-1">Circuit Breaker <a class="header-anchor" href="#circuit-breaker" aria-label="Permalink to &quot;Circuit Breaker&quot;">​</a></h2><p>Arquivo: <code>app/core/circuit_breaker.py</code></p><p>Pattern Circuit Breaker com estado em Redis (compartilhado entre workers).</p><h3 id="estados" tabindex="-1">Estados <a class="header-anchor" href="#estados" aria-label="Permalink to &quot;Estados&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLOSED → (falhas &gt;= threshold) → OPEN → (recovery_timeout) → HALF_OPEN → (sucesso) → CLOSED</span></span>
<span class="line"><span>                                                              → (falha) → OPEN</span></span></code></pre></div><h3 id="configuracao" tabindex="-1">Configuracao <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuracao&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parametro</th><th>Default</th><th>Descricao</th></tr></thead><tbody><tr><td><code>failure_threshold</code></td><td>5</td><td>Falhas para abrir circuito</td></tr><tr><td><code>recovery_timeout</code></td><td>300s</td><td>Tempo ate HALF_OPEN</td></tr><tr><td><code>failure_window</code></td><td>300s</td><td>Janela deslizante de contagem</td></tr></tbody></table><h3 id="instancias-pre-configuradas-13" tabindex="-1">Instancias pre-configuradas (13) <a class="header-anchor" href="#instancias-pre-configuradas-13" aria-label="Permalink to &quot;Instancias pre-configuradas (13)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Instancia</th><th>Servico</th><th>Threshold</th><th>Recovery</th></tr></thead><tbody><tr><td><code>serpapi_circuit</code></td><td>SerpAPI</td><td>5</td><td>300s</td></tr><tr><td><code>social_reverse_circuit</code></td><td>Social Reverse</td><td>5</td><td>300s</td></tr><tr><td><code>discord_circuit</code></td><td>Discord API</td><td>5</td><td>300s</td></tr><tr><td><code>reddit_circuit</code></td><td>Reddit API</td><td>5</td><td>300s</td></tr><tr><td><code>google_alerts_circuit</code></td><td>Google Alerts</td><td>5</td><td>600s</td></tr><tr><td><code>twitter_circuit</code></td><td>Twitter API</td><td>5</td><td>300s</td></tr><tr><td><code>darkweb_circuit</code></td><td>Tor SOCKS5</td><td>3</td><td>600s</td></tr><tr><td><code>instagram_circuit</code></td><td>Instagram</td><td>5</td><td>300s</td></tr><tr><td><code>facebook_circuit</code></td><td>Facebook</td><td>5</td><td>600s</td></tr><tr><td><code>flickr_circuit</code></td><td>Flickr</td><td>5</td><td>300s</td></tr><tr><td><code>telegram_circuit</code></td><td>Telegram</td><td>5</td><td>300s</td></tr><tr><td><code>ddg_circuit</code></td><td>DuckDuckGo</td><td>5</td><td>300s</td></tr><tr><td><code>google_direct_circuit</code></td><td>Google Direct</td><td>3</td><td>600s</td></tr></tbody></table><p>Alem dessas, circuit breakers dinamicos por dominio para o crawler (Crawler) via <code>get_domain_circuit(domain)</code>, com threshold=3 e recovery=600s.</p><h3 id="fail-open" tabindex="-1">Fail-open <a class="header-anchor" href="#fail-open" aria-label="Permalink to &quot;Fail-open&quot;">​</a></h3><p>Se Redis estiver indisponivel, circuito assume CLOSED (permite requests). Isso garante que uma falha no Redis nao derrube todos os motores.</p><h3 id="visibilidade-admin" tabindex="-1">Visibilidade admin <a class="header-anchor" href="#visibilidade-admin" aria-label="Permalink to &quot;Visibilidade admin&quot;">​</a></h3><p>Health check em <code>/admin/system/health</code> mostra estado de cada circuit breaker.</p><hr><h2 id="integracao" tabindex="-1">Integracao <a class="header-anchor" href="#integracao" aria-label="Permalink to &quot;Integracao&quot;">​</a></h2>`,36)),(d(),n(h,null,{default:r(()=>[u(o,{id:"mermaid-524",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5BRequest%5D%20--%3E%20B%5BSSRF%20Guard%5D%0A%20%20%20%20B%20--%3E%20C%5BBlock%20Detector%5D%0A%20%20%20%20C%20--%3E%20D%5BCircuit%20Breaker%5D%0A%20%20%20%20D%20--%3E%20E%5BExternal%20Service%5D%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[a(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e("p",null,"O fluxo completo para qualquer request externo:",-1)),t[3]||(t[3]=e("ol",null,[e("li",null,[e("strong",null,"SSRF Guard"),a(" valida a URL antes de qualquer conexao")]),e("li",null,[e("strong",null,"Block Detector"),a(" analisa a resposta recebida")]),e("li",null,[e("strong",null,"Circuit Breaker"),a(" contabiliza falhas e interrompe requests se necessario")])],-1))])}const S=i(p,[["render",m]]);export{v as __pageData,S as default};
